function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function asArr(v) { return Array.isArray(v) ? v.filter(Boolean).map(safeStr) : []; }

function getAiText(j) {
  if (typeof j.content === 'string') return j.content;
  if (typeof j.text === 'string') return j.text;
  if (j.message && typeof j.message.content === 'string') return j.message.content;
  if (Array.isArray(j.choices) && j.choices[0] && j.choices[0].message) return safeStr(j.choices[0].message.content);
  if (Array.isArray(j.output)) {
    const msg = j.output.find(function(o) { return o && o.type === 'message' && Array.isArray(o.content); });
    const part = msg && msg.content.find(function(c) { return c && typeof c.text === 'string'; });
    if (part) return part.text;
  }
  return safeStr(JSON.stringify(j));
}

function extractJson(text) {
  const t = safeStr(text).replace(/```json/gi, '```').replace(/```/g, '');
  const start = t.indexOf('{');
  const end = t.lastIndexOf('}');
  if (start === -1 || end === -1 || end < start) return null;
  try { return JSON.parse(t.substring(start, end + 1)); } catch (e) { return null; }
}

const base = $('Normalisiere Eingabe').item.json;
const aiText = getAiText($json);
const parsed = extractJson(aiText);

if (!parsed) {
  return {
    json: {
      vorgangKey: base.vorgangKey,
      vorgangsnummer: base.vorgangsnummer,
      imageHeadline: base.imageHeadline,
      imageSubline: base.imageSubline,
      visualMetaphor: '', visualPflichtobjekte: [], visualPflichthandlung: '',
      visualBetroffene: [], visualOrt: '', visualUeberzeichnung: '',
      visualErkennungssatz: '', visualVerboteneErsatzmotive: [],
      imagePrompt: '', imageNegativePrompt: '', altText: '',
      sensitiveTopicDetected: false, sensitiveGroup: '',
      parseError: true
    }
  };
}

return {
  json: {
    vorgangKey: base.vorgangKey,
    vorgangsnummer: base.vorgangsnummer,
    imageHeadline: base.imageHeadline,
    imageSubline: base.imageSubline,
    visualMetaphor: safeStr(parsed.visualMetaphor),
    visualPflichtobjekte: asArr(parsed.visualPflichtobjekte),
    visualPflichthandlung: safeStr(parsed.visualPflichthandlung),
    visualBetroffene: asArr(parsed.visualBetroffene),
    visualOrt: safeStr(parsed.visualOrt),
    visualUeberzeichnung: safeStr(parsed.visualUeberzeichnung),
    visualErkennungssatz: safeStr(parsed.visualErkennungssatz),
    visualVerboteneErsatzmotive: asArr(parsed.visualVerboteneErsatzmotive),
    imagePrompt: safeStr(parsed.imagePrompt),
    imageNegativePrompt: safeStr(parsed.imageNegativePrompt),
    altText: safeStr(parsed.altText),
    sensitiveTopicDetected: parsed.sensitiveTopicDetected === true,
    sensitiveGroup: safeStr(parsed.sensitiveGroup),
    parseError: false
  }
};
